1	// Unified bridge-token extraction. Replaces the three separate
2	// extract*Tokens functions that index.ts defined inline. Covers:
3	//
4	//   <<SEND_FILE:abs-path>>      — existing
5	//   <<SCHEDULE:time|prompt>>    — existing
6	//   <<ASK:question_id|...>>     — existing
7	//   <<SKILL_USED:name|reason>>  — new (AB-1)
8	//   <<GOAL_DONE:reason>>        — new (AB-1)
9	//
10	// Token syntax, limits, and semantics are defined by
11	// `docs/ab-token-protocol.md`. This module is the one extraction path —
12	// no parallel implementations anywhere.
13	//
14	// Design notes:
15	//
16	//  • Code-region masking is mandatory for every regex. Agents frequently
17	//    paste token examples inside ``` fenced or `inline` code blocks to
18	//    explain the protocol; without masking those examples would be
19	//    treated as live tokens and accidentally trigger real side effects.
20	//    The mask/restore pair lives here and is private — callers don't
21	//    need to know about sentinels.
22	//
23	//  • ASK parsing keeps its full-featured parseAskInner function inline
24	//    here so SKILL_USED's simpler parser can sit next to it. The
25	//    Telegram-UI layer (buildAskKeyboard / askRegistry / replyWithAsk)
26	//    stays in index.ts — that's not transformation, it's rendering.
27	//
28	//  • SCHEDULE's time-parsing dependencies (parseDuration,
29	//    parseAbsoluteTime, parseRecurrence, computeNextRunAt) are injected
30	//    via the `scheduleParsers` parameter of `transform()` so this file
31	//    doesn't pull in the whole schedule-store module graph.
32	
33	import type { Recurrence } from "./recurrence.js";
34	import { STICKER_MAP } from "./stickerMap.js";
35	
36	// ───────────────────────────────────────────────────────────────────────
37	// Regexes — one per token. Each is anchored with `<<NAME:` prefix and
38	// terminates at `>>`. Payload body rejects `>` and CRLF so a stray `>`
39	// inside the payload terminates cleanly instead of eating downstream
40	// tokens.
41	// ───────────────────────────────────────────────────────────────────────
42	export const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
43	export const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
44	export const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
45	// 2026-05-02: reason bodies additionally reject `<` so an agent quoting
46	// other tokens inside a reason (e.g. <<GOAL_DONE:describes <<RESTART:foo>>>>)
47	// can't collapse the outer match onto the inner `>>`. SEND_FILE / SCHEDULE
48	// / ASK bodies keep `<` allowed because their payloads (paths / time specs
49	// / key=val) don't typically contain it, and banning `<` there would break
50	// legitimate payloads like URLs.
51	export const SKILL_USED_RE =
52	  /<<SKILL_USED:\s*([a-zA-Z0-9_-]{1,60})\s*\|\s*([^<>|\r\n]{0,500})\s*>>/g;
53	export const GOAL_DONE_RE = /<<GOAL_DONE:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
54	// RESTART token (C3, 2026-05-02). `<<RESTART:reason>>` or bare
55	// `<<RESTART>>` asks the bridge to exit(1) so the supervisor respawns us.
56	// The actual guardrail (goal active? cooldown? cap?) lives in runPrompt;
57	// this regex only extracts the payload. Reason is 1-500 chars, rejects
58	// `<` / `>` / `|` / CRLF so malformed payloads (including agents quoting
59	// other tokens inside the reason) fall through as visible text instead
60	// of collapsing the match on a nested `>>`.
61	export const RESTART_RE = /<<RESTART:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
62	export const RESTART_BARE_RE = /<<RESTART>>/g;
63	export const RESTART_BARE_REASON = "agent-requested-restart";
64	export const STICKER_RE = /<<STICKER:\s*([a-z_]{1,20})\s*>>/g;
65	export const CONTINUE_RE = /<<CONTINUE>>/g;
66	
67	// ASK sub-regexes (kept here because ASK payload parsing lives here too).
68	const ASK_ID_RE = /^[a-zA-Z0-9_-]{1,32}$/;
69	const ASK_KEY_RE = /^[a-zA-Z0-9_-]{1,20}$/;
70	const ASK_LABEL_MAX = 40;
71	// Soft cap: labels over this width are accepted but logged. The skill
72	// (ms-telegram-ask-button-protocol) mandates >20 -> numbered body list
73	// with short labels. We do not reject here because rejecting would
74	// leave the whole token verbatim in chat; a log line gives operators
75	// something to grep when a user reports crowded/unreadable buttons.
76	const ASK_LABEL_SOFT = 20;
77	
78	// Token-class limits (match docs/ab-token-protocol.md).
79	export const SCHEDULE_PROMPT_MAX = 1000;
80	export const SCHEDULE_MAX_PER_MSG = 3;
81	export const SKILL_USED_MAX_PER_MSG = 5;
82	export const GOAL_DONE_MAX_PER_MSG = 1;
83	// RESTART: only honour the first <<RESTART:...>> in one reply. Extra
84	// tokens stay in visible text as a signal to the agent (same idea as
85	// GOAL_DONE extra-token handling).
86	export const RESTART_MAX_PER_MSG = 1;
87	// 2026-05-03: balanced-body reason cap raised from 200 → 500 and
88	// switched from hard-reject to silent truncate. Live-observed agent
89	// failure mode: when a goal takes 10+ turns to complete, the GOAL_DONE
90	// reason summarising "why I think we're done" routinely runs 300-600
91	// chinese chars. The old 200-char hard reject left the token verbatim
92	// in text, goalDone=null, and the bridge kept scheduling continuation
93	// turns forever ("GOAL_DONE failed to fire" bug fact, 2026-05-03).
94	// Truncate keeps the token functional while preserving a sane upper
95	// bound that fits comfortably in the "✓ Goal achieved: <reason>" line
96	// on Telegram. Same cap applied to SKILL_USED and RESTART for policy
97	// consistency.
98	export const BALANCED_REASON_MAX = 500;
99	
100	// ───────────────────────────────────────────────────────────────────────
101	// Payload interfaces
102	// ───────────────────────────────────────────────────────────────────────
103	export interface AskOption {
104	  key: string;
105	  label: string;
106	  recommended: boolean;
107	}
108	
109	export interface AskEntry {
110	  questionId: string;
111	  options: AskOption[];
112	}
113	
114	export interface ScheduleTokenEntry {
115	  runAt: number;
116	  prompt: string;
117	  whenLabel: string;
118	  recurrence?: Recurrence;
119	}
120	
121	export interface SkillUsageEntry {
122	  name: string;
123	  reason: string;
124	}
125	
126	export interface GoalDoneEntry {
127	  reason: string;
128	}
129	
130	/** Payload of a valid <<RESTART:reason>> token. C3 (2026-05-02).
131	 *
132	 * `reason` is trimmed but not otherwise validated here — the guardrail
133	 * layer (goalStore.markRestart + runPrompt) decides whether an empty
134	 * reason is allowed. We just extract; empty reasons still produce an
135	 * entry so the runPrompt layer can surface a proper "empty-reason"
136	 * warning to the user instead of the token silently staying in text. */
137	export interface RestartTokenEntry {
138	  reason: string;
139	}
140	
141	/** Payload of a valid <<SKILL_PROPOSE:name|reason>> token. Agent proposes
142	 *  writing a skill; bridge shows an ASK button for user confirmation. */
143	export interface SkillProposeEntry {
144	  name: string;
145	  reason: string;
146	}
147	
148	/** Payload of a valid <<WIKI_QUERY:slug|summary>> token. Agent decides
149	 *  when a reply warrants a wiki queries/ page and emits this token. */
150	export interface WikiQueryEntry {
151	  slug: string;
152	  summary: string;
153	}
154	
155	/** Payload of <<SPECIALIST_PROXY:name|message>>. Agent decides to hand off
156	 *  the user's message to a specialist in transparent proxy mode. */
157	export interface SpecialistProxyEntry {
158	  name: string;
159	  message: string;
160	}
161	
162	/** Payload of <<MOA_PLAN:{json}>> — raw single-line JSON emitted by the
163	 *  aggregator in MoA plan mode (SPEC-moa-provider Phase 2). Parsing and
164	 *  validation live in moa-plan.ts; this module only captures the span. */
165	export interface MoaPlanEntry {
166	  raw: string;
167	}
168	
169	export interface TransformedReply {
170	  /** Display text with all valid tokens stripped and excess blank lines collapsed. */
171	  text: string;
172	  /** Absolute paths requested via <<SEND_FILE>>. */
173	  sendFiles: string[];
174	  /** Schedules requested via <<SCHEDULE>> (only well-formed, first SCHEDULE_MAX_PER_MSG). */
175	  scheduleTokens: ScheduleTokenEntry[];
176	  /** ASK keyboards to render (de-duped by question_id). */
177	  askTokens: AskEntry[];
178	  /** De-duped skill usage reports (first SKILL_USED_MAX_PER_MSG distinct names). */
179	  skillUsages: SkillUsageEntry[];
180	  /** First GOAL_DONE token; `null` if none present. */
181	  goalDone: GoalDoneEntry | null;
182	  /** First RESTART token; `null` if none present. Guardrail (goal
183	   * active? cooldown? cap? empty reason?) runs in runPrompt, not here. */
184	  restartToken: RestartTokenEntry | null;
185	  /** Sticker emotion keys requested via <<STICKER:emotion>>. */
186	  stickerEmotions: string[];
187	  /** Skill proposal via <<SKILL_PROPOSE:name|reason>>; null if none. */
188	  skillPropose: SkillProposeEntry | null;
189	  /** Wiki query page request via <<WIKI_QUERY:slug|summary>>; null if none. */
190	  wikiQuery: WikiQueryEntry | null;
191	  /** Whether the agent emitted <<CONTINUE>> to request another turn without a goal. */
192	  continueToken: boolean;
193	  /** Specialist proxy handoff via <<SPECIALIST_PROXY:name|message>>; null if none. */
194	  specialistProxy: SpecialistProxyEntry | null;
195	  /** MoA plan JSON via <<MOA_PLAN:{...}>>; null if none. First one wins. */
196	  moaPlan: MoaPlanEntry | null;
197	}
198	
199	/** Parsers injected by caller so this module has no dep on schedule-store. */
200	export interface ScheduleParsers {
201	  parseDuration: (raw: string) => number | null;
202	  parseAbsoluteTime: (raw: string) => Date | null;
203	  parseRecurrence: (raw: string) => Recurrence | null;
204	  computeNextRunAt: (rec: Recurrence, after: number) => number | null;
205	  now?: () => number; // defaults to Date.now — override for tests
206	}
207	
208	// ───────────────────────────────────────────────────────────────────────
209	// Code-region masking
210	// ───────────────────────────────────────────────────────────────────────
211	// Ported verbatim from index.ts's existing maskCodeRegions so refactor is
212	// behavior-preserving. Sentinel uses null bytes so nothing in normal text
213	// can collide with it.
214	const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
215	
216	function maskCodeRegions(text: string): {
217	  masked: string;
218	  restore: (s: string) => string;
219	} {
220	  const slots: string[] = [];
221	  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
222	    const idx = slots.length;
223	    slots.push(m);
224	    return `\u0000CODE${idx}\u0000`;
225	  });
226	  const restore = (s: string) =>
227	    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
228	  return { masked, restore };
229	}
230	
231	// ───────────────────────────────────────────────────────────────────────
232	// ASK parsing (moved from index.ts verbatim — behavior preserved)
233	// ───────────────────────────────────────────────────────────────────────
234	function parseAskInner(inner: string): AskEntry | null {
235	  const reject = (reason: string): null => {
236	    const preview = inner.length > 80 ? `${inner.slice(0, 77)}...` : inner;
237	    console.warn(`[ASK] malformed token rejected: ${reason} | inner="${preview}"`);
238	    return null;
239	  };
240	  const parts = inner.split("|").map((s) => s.trim());
241	  if (parts.length < 2) return reject("need at least question_id + 1 option");
242	  const questionId = parts[0];
243	  if (!ASK_ID_RE.test(questionId)) {
244	    return reject(
245	      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`,
246	    );
247	  }
248	  const options: AskOption[] = [];
249	  const keys = new Set<string>();
250	  let recommendedCount = 0;
251	  for (const raw of parts.slice(1)) {
252	    if (!raw) continue;
253	    let spec = raw;
254	    let recommended = false;
255	    if (spec.startsWith("*")) {
256	      recommended = true;
257	      spec = spec.slice(1);
258	    }
259	    const eq = spec.indexOf("=");
260	    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
261	    const key = spec.slice(0, eq).trim();
262	    const label = spec.slice(eq + 1).trim();
263	    if (!ASK_KEY_RE.test(key)) {
264	      return reject(
265	        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`,
266	      );
267	    }
268	    if (!label) return reject(`key "${key}" has empty label`);
269	    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
270	      // Soft-cap warning only; see ASK_LABEL_SOFT definition above for rationale.
271	      console.warn(
272	        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
273	      );
274	    }
275	    if (label.length > ASK_LABEL_MAX) {
276	      return reject(
277	        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`,
278	      );
279	    }
280	    if (keys.has(key)) return reject(`duplicate key "${key}"`);
281	    keys.add(key);
282	    if (recommended && recommendedCount > 0) recommended = false;
283	    if (recommended) recommendedCount++;
284	    options.push({ key, label, recommended });
285	  }
286	  if (options.length < 1) return reject("no valid options");
287	  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
288	  return { questionId, options };
289	}
290	
291	// ───────────────────────────────────────────────────────────────────────
292	// Balanced scanner for tokens with free-form reason bodies (GOAL_DONE /
293	// SKILL_USED / RESTART). Regex alone can't handle an agent that quotes
294	// another token inside a reason (e.g. `<<GOAL_DONE:describes <<RESTART:
295	// foo>> here>>`) because non-greedy `+?` collapses on the inner `>>`
296	// and greedy `+` overshoots past the real closer. The scanner walks the
297	// string tracking `<<` / `>>` depth so outer tokens consume any nested
298	// literals before the narrower per-token regexes have a chance to see
299	// them.
300	//
301	// Design notes:
302	//   • Tokens are required to stay on a single line (spec §1.1/1.2/1.3).
303	//     A `\n` inside a candidate span aborts the match and the opener
304	//     stays visible.
305	//   • Sentinel `\u0000CODE<n>\u0000` from code-region masking does not
306	//     contain `<<` or `>>`, so scanner is safe to run on masked text.
307	//   • Scanner is O(n) per call (single forward pass with a counter).
308	//   • `runBalancedPhase` handles all three balanced-body prefixes in
309	//     one pass so an outer `<<RESTART:...>>` containing an inner
310	//     `<<GOAL_DONE:...>>` literal is consumed atomically without the
311	//     inner token being extracted as a real GOAL_DONE.
312	// ───────────────────────────────────────────────────────────────────────
313	/** Run balanced-scanner phase for multiple token prefixes in a single
314	 *  forward pass over `text`. At each `<<PREFIX:` encountered (first
315	 *  match against any registered prefix wins — they don't overlap because
316	 *  all prefixes are `<<UPPERCASE:`), we find the matching top-level
317	 *  `>>` and hand the inner substring to that prefix's handler.
318	 *
319	 *  This outer-first strategy is what prevents a nested `<<GOAL_DONE:>>`
320	 *  inside a `<<RESTART:...>>` reason from being extracted as a real
321	 *  GOAL_DONE: the scanner sees the `<<RESTART:` opener first, walks to
322	 *  its balanced closer (tracking depth so inner `<<>>` pairs don't
323	 *  prematurely close), and consumes the whole span atomically.
324	 *
325	 *  Handler semantics (same as `replaceBalancedTokens`):
326	 *    • returns string → replaces the full `<<PREFIX:...>>` span
327	 *    • returns null  → token left verbatim, scanner continues past it
328	 *
329	 *  Newlines abort a candidate span (tokens are single-line per spec);
330	 *  the scanner falls past the opener and keeps searching.
331	 */
332	function runBalancedPhase(
333	  text: string,
334	  handlers: Record<string, (inner: string) => string | null>,
335	): string {
336	  const prefixes = Object.keys(handlers);
337	  let out = "";
338	  let cursor = 0;
339	  while (cursor < text.length) {
340	    // Find the earliest occurrence of ANY registered prefix at or after cursor.
341	    let bestStart = -1;
342	    let bestPrefix = "";
343	    for (const p of prefixes) {
344	      const idx = text.indexOf(p, cursor);
345	      if (idx >= 0 && (bestStart < 0 || idx < bestStart)) {
346	        bestStart = idx;
347	        bestPrefix = p;
348	      }
349	    }
350	    if (bestStart < 0) {
351	      out += text.slice(cursor);
352	      break;
353	    }
354	    // Walk for balanced closer starting after the opener.
355	    const innerStart = bestStart + bestPrefix.length;
356	    let depth = 1;
357	    let i = innerStart;
358	    let aborted = false;
359	    let closedAt = -1;
360	    while (i < text.length - 1) {
361	      const c = text.charCodeAt(i);
362	      if (c === 0x0a || c === 0x0d) {
363	        aborted = true;
364	        break;
365	      }
366	      if (c === 0x3c && text.charCodeAt(i + 1) === 0x3c) {
367	        depth++;
368	        i += 2;
369	        continue;
370	      }
371	      if (c === 0x3e && text.charCodeAt(i + 1) === 0x3e) {
372	        depth--;
373	        if (depth === 0) {
374	          closedAt = i;
375	          break;
376	        }
377	        i += 2;
378	        continue;
379	      }
380	      i++;
381	    }
382	    if (aborted || closedAt < 0) {
383	      // No valid balanced span for this opener. Skip past the opener
384	      // itself (not past the whole line) so a later prefix can still
385	      // match after it.
386	      out += text.slice(cursor, bestStart + bestPrefix.length);
387	      cursor = bestStart + bestPrefix.length;
388	      continue;
389	    }
390	    const inner = text.slice(innerStart, closedAt);
391	    const end = closedAt + 2;
392	    const replacement = handlers[bestPrefix](inner);
393	    out += text.slice(cursor, bestStart);
394	    if (replacement === null) {
395	      out += text.slice(bestStart, end);
396	    } else {
397	      out += replacement;
398	    }
399	    cursor = end;
400	  }
401	  return out;
402	}
403	
404	
405	/**
406	 * Extract every token class from `rawReply` in one pass. Tokens inside
407	 * code regions are ignored. Malformed tokens are left in the visible
408	 * text as documentation for the agent. All limits come from
409	 * docs/ab-token-protocol.md.
410	 *
411	 * Dependency injection: SCHEDULE time-parsers are passed via `parsers`
412	 * so this module doesn't drag in schedule-store / recurrence graphs.
413	 * Pass `null` (or just omit SCHEDULE parsing entirely) if the caller
414	 * doesn't care about schedules — SCHEDULE tokens then stay in the text.
415	 */
416	export function transform(
417	  rawReply: string,
418	  parsers: ScheduleParsers | null = null,
419	): TransformedReply {
420	  if (!rawReply) {
421	    return {
422	      text: "",
423	      sendFiles: [],
424	      scheduleTokens: [],
425	      askTokens: [],
426	      skillUsages: [],
427	      goalDone: null,
428	      restartToken: null,
429	      stickerEmotions: [],
430	      skillPropose: null,
431	      wikiQuery: null,
432	      continueToken: false,
433	      specialistProxy: null,
434	      moaPlan: null,
435	    };
436	  }
437	
438	  const { masked, restore } = maskCodeRegions(rawReply);
439	
440	  // Collect payloads in a mutable object while we do the .replace passes.
441	  const sendFiles: string[] = [];
442	  const scheduleTokens: ScheduleTokenEntry[] = [];
443	  const askTokens: AskEntry[] = [];
444	  const skillUsages: SkillUsageEntry[] = [];
445	  const seenSkillNames = new Set<string>();
446	  const seenAskIds = new Set<string>();
447	  let goalDone: GoalDoneEntry | null = null;
448	  let restartToken: RestartTokenEntry | null = null;
449	  let skillPropose: SkillProposeEntry | null = null;
450	  let wikiQuery: WikiQueryEntry | null = null;
451	  let specialistProxy: SpecialistProxyEntry | null = null;
452	  let moaPlan: MoaPlanEntry | null = null;
453	
454	  // ────────────────────────────────────────────────────────────────
455	  // Phase 1 — balanced-scanner tokens (free-form reason bodies).
456	  // These run FIRST so that when an agent nests another token inside
457	  // a reason (e.g. `<<GOAL_DONE:... <<RESTART:foo>> ...>>`), the outer
458	  // match consumes the whole span including the nested literal. Later
459	  // phases never see the inner token and can't trigger it by accident.
460	  //
461	  // Single forward pass over `masked`: at each `<<PREFIX:` (for any of
462	  // the three balanced-body token classes), we walk to the matching
463	  // top-level `>>` and hand the inner text to the right handler.
464	  // Crucially, the walk happens before any narrower extractor runs —
465	  // nested `<<...>>` inside a reason is consumed as part of the outer
466	  // span and never appears as an independent token.
467	  // ────────────────────────────────────────────────────────────────
468	
469	  let stripped = runBalancedPhase(masked, {
470	    "<<SKILL_USED:": (inner) => {
471	      if (skillUsages.length >= SKILL_USED_MAX_PER_MSG) return null;
472	      const pipe = inner.indexOf("|");
473	      if (pipe < 0) return null;
474	      const name = inner.slice(0, pipe).trim();
475	      let reason = inner.slice(pipe + 1).trim();
476	      if (!/^[a-zA-Z0-9_-]{1,60}$/.test(name)) return null;
477	      // 2026-05-03: truncate over-length reasons instead of rejecting.
478	      // See BALANCED_REASON_MAX comment for rationale.
479	      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
480	      if (seenSkillNames.has(name)) return ""; // dedup, first reason wins
481	      seenSkillNames.add(name);
482	      skillUsages.push({ name, reason });
483	      return "";
484	    },
485	    "<<GOAL_DONE:": (inner) => {
486	      if (goalDone !== null) return null;
487	      let reason = inner.trim();
488	      if (reason.length < 1) return null;
489	      if (reason.includes("|")) return null;
490	      // 2026-05-03: truncate over-length reasons instead of rejecting.
491	      // Live bug: agent summaries for 10+ turn goals routinely exceeded
492	      // the old 200-char cap and the token was left verbatim, causing
493	      // goalDone=null and an infinite continuation loop.
494	      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
495	      goalDone = { reason };
496	      return "";
497	    },
498	    "<<RESTART:": (inner) => {
499	      if (restartToken !== null) return null;
500	      let reason = inner.trim();
501	      if (reason.includes("|")) return null;
502	      // 2026-05-03: truncate over-length reasons instead of rejecting.
503	      if (reason.length > BALANCED_REASON_MAX) reason = reason.slice(0, BALANCED_REASON_MAX);
504	      // Empty reason → use default so markRestart doesn't reject.
505	      if (!reason) reason = RESTART_BARE_REASON;
506	      restartToken = { reason };
507	      return "";
508	    },
509	    "<<SKILL_PROPOSE:": (inner) => {
510	      if (skillPropose !== null) return null; // only first one
511	      const pipe = inner.indexOf("|");
512	      if (pipe < 0) return null;
513	      const name = inner.slice(0, pipe).trim();
514	      const reason = inner.slice(pipe + 1).trim();
515	      if (!/^[a-z0-9_-]{1,60}$/.test(name)) return null;
516	      if (!reason || reason.length > 500) return null;
517	      skillPropose = { name, reason };
518	      return "";
519	    },
520	    "<<WIKI_QUERY:": (inner) => {
